document.addEventListener("DOMContentLoaded",(()=>{fetch("../assets/data/trip.json").then((e=>e.json())).then((e=>{const t=document.querySelector("main");e.days.forEach((e=>{const n=document.createElement("div");n.classList.add("day");const i=document.createElement("h2");i.classList.add("day-header"),i.innerText=e.day,n.appendChild(i);const c=document.createElement("div");c.classList.add("day-content"),e.checkpoints.forEach((e=>{let t;e.link?(t=document.createElement("a"),t.href=e.link,t.target="_blank"):t=document.createElement("div"),t.classList.add("day-content-checkpoint"),e.class&&t.classList.add(e.class);const n=`\n            <div class="day-content-checkpoint-timeline">\n              <div class="day-content-checkpoint-timeline-time">${e.time}</div>\n              <div class="day-content-checkpoint-timeline-line"></div>\n            </div>\n            <div class="day-content-checkpoint-info">\n              <div class="day-content-checkpoint-info-title">\n                ${e.icon?`<i class="fa-solid ${e.icon}"></i>`:""} ${e.title}\n              </div>\n              <div class="day-content-checkpoint-info-description">${e.description}</div>\n            </div>\n          `;t.innerHTML=n,c.appendChild(t)})),n.appendChild(c),t.appendChild(n),i.addEventListener("click",(()=>{c.classList.toggle("expanded")}))}))})).catch((e=>console.error("Error loading itinerary:",e))),fetch("https://api.weatherapi.com/v1/current.json?key=0bc7f2f831a14bf8b93154800240707&q=Pompei&aqi=no").then((e=>e.json())).then((e=>{document.getElementById("weather-info").innerHTML=`\n      <div class="weather-item"><i class="fas fa-thermometer-half"></i> ${e.current.temp_c} °C</div>\n      <div class="weather-item"><i class="fas fa-cloud"></i> ${e.current.condition.text}</div>\n      <div class="weather-item"><i class="fas fa-tint"></i> ${e.current.humidity}%</div>\n      <div class="weather-item"><i class="fas fa-wind"></i> ${e.current.wind_kph} kph</div>\n      `})).catch((e=>console.error("Error fetching weather data:",e)))}));